export const getGetHabitCompletionsUrl = (id: number,
    params?: GetHabitCompletionsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/habits/${id}/completions?${stringifiedParams}` : `/api/habits/${id}/completions`
}

